import{_ as a,d as o,e as d,a as r,b as e,c as i,f as l}from"./chunks/添加dc新渠道配置.jxAOeu6M.js";import{_ as s,o as c,c as n,a2 as h}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Discord チャンネルの追加","description":"","frontmatter":{},"headers":[],"relativePath":"ja-JP/upload/discord.md","filePath":"ja-JP/upload/discord.md","lastUpdated":1781962217000}'),p={name:"ja-JP/upload/discord.md"};function m(_,t,b,D,u,B){return c(),n("div",null,[...t[0]||(t[0]=[h('<h1 id="discord-チャンネルの追加" tabindex="-1">Discord チャンネルの追加 <a class="header-anchor" href="#discord-チャンネルの追加" aria-label="Permalink to &quot;Discord チャンネルの追加&quot;">​</a></h1><p>Discord チャンネルを使うと、Discord サーバー内のチャンネルをファイル保存先として利用できます。</p><h2 id="事前に用意するもの" tabindex="-1">事前に用意するもの <a class="header-anchor" href="#事前に用意するもの" aria-label="Permalink to &quot;事前に用意するもの&quot;">​</a></h2><table tabindex="0"><thead><tr><th>必要なもの</th><th>用途</th></tr></thead><tbody><tr><td>Discord アカウント</td><td>サーバーと Bot を管理します</td></tr><tr><td>Discord サーバー</td><td>保存先チャンネルを置く場所</td></tr><tr><td>Discord Bot</td><td>ファイル投稿に使います</td></tr><tr><td>Bot Token</td><td>ImgBed から Bot を呼び出すために使います</td></tr><tr><td>チャンネル ID</td><td>投稿先チャンネルを指定します</td></tr></tbody></table><h2 id="サーバーを作成する" tabindex="-1">サーバーを作成する <a class="header-anchor" href="#サーバーを作成する" aria-label="Permalink to &quot;サーバーを作成する&quot;">​</a></h2><p>保存用の Discord サーバーを作成します。既存サーバーを使っても構いませんが、運用しやすいように専用サーバーを用意するのがおすすめです。</p><p><img src="'+a+'" alt="サーバー作成" loading="lazy"></p><h2 id="開発者モードを有効にする" tabindex="-1">開発者モードを有効にする <a class="header-anchor" href="#開発者モードを有効にする" aria-label="Permalink to &quot;開発者モードを有効にする&quot;">​</a></h2><p>チャンネル ID をコピーするには、Discord の開発者モードを有効にします。</p><p><img src="'+o+'" alt="開発者モード" loading="lazy"></p><p>対象チャンネルを右クリックし、チャンネル ID をコピーします。</p><p><img src="'+d+'" alt="チャンネル ID" loading="lazy"></p><h2 id="bot-を作成し-token-を取得する" tabindex="-1">Bot を作成し Token を取得する <a class="header-anchor" href="#bot-を作成し-token-を取得する" aria-label="Permalink to &quot;Bot を作成し Token を取得する&quot;">​</a></h2><p>Discord Developer Portal でアプリケーションを作成し、Bot を追加します。Bot Token をコピーして安全に保管します。</p><p><img src="'+r+'" alt="Bot Token" loading="lazy"></p><h2 id="bot-をサーバーへ招待する" tabindex="-1">Bot をサーバーへ招待する <a class="header-anchor" href="#bot-をサーバーへ招待する" aria-label="Permalink to &quot;Bot をサーバーへ招待する&quot;">​</a></h2><p>OAuth2 設定で Bot 権限を選び、生成した招待 URL からサーバーへ Bot を追加します。</p><p><img src="'+e+'" alt="Bot 権限" loading="lazy"></p><p><img src="'+i+'" alt="Bot 招待" loading="lazy"></p><p>Bot には投稿先チャンネルへメッセージ送信と添付ファイル送信の権限が必要です。</p><h2 id="imgbed-へ入力する" tabindex="-1">ImgBed へ入力する <a class="header-anchor" href="#imgbed-へ入力する" aria-label="Permalink to &quot;ImgBed へ入力する&quot;">​</a></h2><p>アップロード設定で <code>Discord</code> を選び、次を入力します。</p><table tabindex="0"><thead><tr><th>項目</th><th>入力内容</th></tr></thead><tbody><tr><td>チャンネル名</td><td>例：<code>Discord Storage</code></td></tr><tr><td>Bot Token</td><td>Developer Portal で取得した Token</td></tr><tr><td>Channel ID</td><td>投稿先チャンネルの ID</td></tr><tr><td>備考</td><td>任意</td></tr></tbody></table><p><img src="'+l+'" alt="Discord 設定" loading="lazy"></p><h2 id="確認方法" tabindex="-1">確認方法 <a class="header-anchor" href="#確認方法" aria-label="Permalink to &quot;確認方法&quot;">​</a></h2><ol><li>保存後に Discord チャンネルカードが表示される。</li><li>テスト画像をアップロードする。</li><li>Discord の対象チャンネルにファイルが投稿される。</li><li>ImgBed が返すリンクを開ける。</li></ol><p>失敗する場合は、Bot Token、Channel ID、Bot の権限、サーバーへの参加状態を確認してください。</p>',27)])])}const P=s(p,[["render",m]]);export{f as __pageData,P as default};
